const reminders = $('Fetch Julian reminders').first().json;
const allCandidates = $('Fetch new discovery candidates').all().map(i => i.json);

// Julian's ML/AI keyword filter
const ML_KEYWORDS = [
  'ml', 'machine learning', 'data engineering', 'data science', 'ai ', 'artificial intelligence',
  'nlp', 'llm', 'mlops', 'deep learning', 'data infrastructure', 'analytics engineer',
  'platform engineer', 'backend engineer', 'software engineer intern', 'data intern',
  'python', 'pytorch', 'spark', 'pyspark', 'aws'
];

const matchesMlProfile = (c) => {
  const text = `${c.detected_job_title || ''} ${c.company_name || ''}`.toLowerCase();
  return ML_KEYWORDS.some(kw => text.includes(kw));
};

const mlCandidates = allCandidates.filter(matchesMlProfile);

// Build message
const now = new Date();
const hour = now.getHours();
const greeting = hour < 12 ? '☀️ Buenos días' : hour < 18 ? '🌤 Buenas tardes' : '🌙 Buenas noches';

let msg = `${greeting}, Julian.\n`;
msg += `🤖 *JARVIS — Pipeline Report*\n`;
msg += `📅 ${now.toLocaleDateString('es-CO', {weekday:'long', day:'numeric', month:'long'})}\n\n`;

// Application reminders
const appReminders = Array.isArray(reminders.top_items)
  ? reminders.top_items.filter(r => r.related_entity_type === 'application')
  : [];

if (appReminders.length > 0) {
  msg += `📋 *Tus aplicaciones con acción pendiente:*\n`;
  for (const r of appReminders.slice(0, 5)) {
    const icon = r.severity === 'high' ? '🔴' : r.severity === 'medium' ? '🟡' : '🟢';
    msg += `${icon} ${r.description}\n`;
  }
  msg += '\n';
} else {
  msg += `✅ Sin acciones pendientes en tus aplicaciones.\n\n`;
}

// ML/AI matching candidates
if (mlCandidates.length > 0) {
  msg += `🎯 *${mlCandidates.length} candidatos ML/AI disponibles para revisar:*\n`;
  for (const c of mlCandidates.slice(0, 8)) {
    const score = c.confidence_score || 0;
    const icon = score >= 0.7 ? '🟢' : score >= 0.5 ? '🟡' : '🔴';
    const title = c.detected_job_title || 'Posición';
    const company = c.company_name || 'Empresa';
    const url = c.detected_job_url ? `\n   [Ver oferta](${c.detected_job_url})` : '';
    msg += `${icon} *${company}*: ${title}${url}\n`;
  }
  if (mlCandidates.length > 8) {
    msg += `_...${mlCandidates.length - 8} más en el dashboard_\n`;
  }
  msg += `\n👉 [Revisar candidatos](http://localhost:3001/discovery)`;
} else {
  msg += `🔍 Sin nuevos candidatos ML/AI hoy.\n`;
  msg += `👉 [Ver dashboard](http://localhost:3001)`;
}

const hasAnything = appReminders.length > 0 || mlCandidates.length > 0;

return [{
  json: {
    message: msg,
    should_notify: hasAnything,
    ml_candidates_count: mlCandidates.length,
    app_reminders_count: appReminders.length,
    total_pending: allCandidates.length
  }
}];
